<!DOCTYPE html><html><head><meta charset="utf-8"><title>{{ $procedure->procedure_number }}</title><style>body{font-family:Arial,sans-serif}.box{border:1px solid #999;padding:10px;margin:8px 0}@media print{button{display:none}}</style></head><body><h2>{{ currentFacility()?->name }} - Dental Procedure Report</h2><p>{{ $procedure->patient->fullName() }} · {{ $procedure->procedure_number }}</p><div class="box"><p><strong>Procedure:</strong> {{ $procedure->procedure_name_snapshot }}</p><p><strong>Tooth:</strong> {{ $procedure->tooth_number }} · <strong>Surfaces:</strong> {{ implode(', ', $procedure->surfaces ?? []) }}</p><p><strong>Anaesthesia:</strong> {{ $procedure->anaesthesia_type }} {{ $procedure->anaesthetic_used }}</p><p><strong>Notes:</strong> {{ $procedure->technique_notes }}</p><p><strong>Instructions:</strong> {{ $procedure->post_procedure_instructions }}</p></div><p>Provider: {{ $procedure->encounter->provider?->name }}</p><button onclick="window.print()">Print</button></body></html>
